export const CLI_RUNNER_IDS = ['claudecode','codex','opencode','openclaw','hermes','aider'] as const;
export type CliRunnerId = typeof CLI_RUNNER_IDS[number];
export const CLI_RUNNERS = new Set<string>(CLI_RUNNER_IDS);
export const SELF_COMPLETING_RUNNERS = new Set<string>(CLI_RUNNER_IDS.filter(r => r !== 'claudecode'));
export function isCliRunner(agent: any): boolean { return CLI_RUNNERS.has(String(agent?.runner || '').toLowerCase()); }

