_editTaskField(this: any, agentId, taskId, field: string, value: any, { by = 'user', applyExtra }: { by?: string; applyExtra?: (task: any) => void } = {}) {
  const agent = this.agents.get(agentId); if (!agent) return null;
  const task = this._getAgentTasks(agentId).find(t => t.id === taskId); if (!task) return null;
  const oldValue = task[field] ?? null;
  task[field] = value;
  applyExtra?.(task);
  (task.history ||= []).push({ status: task.status, at: new Date().toISOString(), by, type: 'edit', field, oldValue, newValue: value ?? null });
  saveTaskToDb({ ...task, agentId });
  this._emit('agent:updated', this._sanitize(agent));
  return task;
}

Public methods become 1-3 line wrappers, e.g. updateTaskRepo(a, t, name, prov) => this._editTaskField(a, t, 'repoFullName', name || null, { applyExtra: task => { task.repoProvider = name ? (prov || task.repoProvider || 'github') : null; } }). Public API unchanged.

