_markTaskStopped(this: any, task: any, ownerAgentId: string, stopTimestamp: string): void {
  if (task.executionStatus !== 'stopped') {
    task.executionStatus = 'stopped';
    task.startedAt = null;
    (task.history ||= []).push({ status: task.status, at: stopTimestamp, by: 'user', type: 'stopped' });
    saveTaskToDb({ ...task, agentId: ownerAgentId });
  }
  setTaskSignal(task.id, 'stopped', true);
  this._emit('task:updated', { agentId: ownerAgentId, task: { ...task, agentId: ownerAgentId } });
}

