_releaseChat(this: any, id: string, isTopLevel: boolean, status: 'idle' | null = 'idle') {
  if (status) this.setStatus(id, status);
  this.abortControllers.delete(id);
  if (isTopLevel) this._chatLocks.delete(id);
}
_failChat(this: any, agent: any, id: string, isTopLevel: boolean, err: any, finalStatus: 'error' | 'idle' = 'error'): never {
  this.abortControllers.delete(id);
  agent.metrics.errors += 1;
  agent.currentThinking = '';
  this._emit('agent:thinking', { agentId: id, agentName: agent.name, project: agent.project || null, thinking: '' });
  this.setStatus(id, finalStatus, err.message);
  saveAgent(agent);
  if (isTopLevel) this._chatLocks.delete(id);
  throw err;
}

